document.addEventListener("DOMContentLoaded",()=>{const n=document.getElementById("search-toggle"),e=document.getElementById("mobile-search");n&&e&&n.addEventListener("click",()=>{e.classList.toggle("hidden"),e.classList.contains("hidden")||new PagefindUI({element:"#pagefind-mobile",translations:{placeholder:"Fahrzeug suchen...",zero_results:'Keine Ergebnisse für "[SEARCH_TERM]"'}})})});
